      iex> compiled = optimizer.compile(
      ...> student,
      ...> trainset=trainset,
      ...> valset=valset,
      ...> strategy="p -> w"
      ...> )
      iex> print(f"Best score: {compiled.candidate_programs[0]['score']}")

